protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator property changed from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing documents and direct SQL queries keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve the "Product|123" format so existing 500K documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // Removed HasIndex — EF Core 9 Cosmos provider now throws on HasIndex calls.
    // Manage indexing through the container's indexing policy (Azure Portal / Bicep / Terraform).
}

